void ECGScreenViewBase::buttonCallbackHandler(const touchgfx::AbstractButton& src)
{
    if (&src == &startButton)
    {
        //Interaction1
        //When startButton clicked call virtual function
        //Call function8
        function8();
    }
    if (&src == &pauseButton)
    {
        //Interaction2
        //When pauseButton clicked call virtual function
        //Call pauseECG
        pauseECG();
    }
    if (&src == &homeButton)
    {
        //Interaction3
        //When homeButton clicked change screen to HomeScreen
        //Go to HomeScreen with screen transition towards West
        application().gotoHomeScreenScreenSlideTransitionWest();
    }
    if (&src == &resetButton)
    {
        //resetECG
        //When resetButton clicked call virtual function
        //Call resetECG
        resetECG();
    }
}
